export const formatCurrency = (amount: number, currency: string = 'USD') => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
  }).format(amount);
};

export const formatDate = (dateString: string) => {
  const options: Intl.DateTimeFormatOptions = { year: 'numeric', month: 'long', day: 'numeric' };
  return new Date(dateString).toLocaleDateString(undefined, options);
};

export const calculateSalesForecast = (salesData: number[]) => {
  const totalSales = salesData.reduce((acc, sale) => acc + sale, 0);
  const averageSales = totalSales / salesData.length;
  return averageSales * 30; // Forecast for next 30 days
};

export const generateCSV = (data: any[], headers: string[]) => {
  const csvRows = [headers.join(',')];
  data.forEach(item => {
    const values = headers.map(header => item[header]);
    csvRows.push(values.join(','));
  });
  return csvRows.join('\n');
};

export const validateEmail = (email: string) => {
  const re = /^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$/;
  return re.test(email);
};
